     1→//! Built-in protocol detectors.
     2→
     3→use crate::types::{
     4→    DetectionContext, DetectionMethod, DetectionResult, ProtocolDetector, ProtocolId,
     5→    TransportLayer,
     6→};
     7→use std::collections::HashMap;
     8→
     9→/// Static port → protocol mapping detector.
    10→pub struct PortMappingDetector {
    11→    tcp_mappings: HashMap<u16, ProtocolId>,
    12→    udp_mappings: HashMap<u16, ProtocolId>,
    13→}
    14→
    15→impl PortMappingDetector {
    16→    pub fn with_defaults() -> Self {
    17→        let mut tcp_mappings = HashMap::new();
    18→        tcp_mappings.insert(50051, ProtocolId::new(ProtocolId::GRPC));
    19→        tcp_mappings.insert(80, ProtocolId::new(ProtocolId::HTTP2));
    20→        tcp_mappings.insert(8080, ProtocolId::new(ProtocolId::HTTP2));
    21→        tcp_mappings.insert(443, ProtocolId::new(ProtocolId::HTTP2));
    22→        tcp_mappings.insert(8443, ProtocolId::new(ProtocolId::HTTP2));
    23→        tcp_mappings.insert(5555, ProtocolId::new(ProtocolId::ZMTP));
    24→        tcp_mappings.insert(5556, ProtocolId::new(ProtocolId::ZMTP));
    25→
    26→        let mut udp_mappings = HashMap::new();
    27→        // RTPS common port range: 7400-7500
    28→        for port in 7400..=7500 {
    29→            udp_mappings.insert(port, ProtocolId::new(ProtocolId::RTPS));
    30→        }
    31→
    32→        Self {
    33→            tcp_mappings,
    34→            udp_mappings,
    35→        }
    36→    }
    37→
    38→    pub fn add_tcp_mapping(&mut self, port: u16, protocol: ProtocolId) {
    39→        self.tcp_mappings.insert(port, protocol);
    40→    }
    41→
    42→    pub fn add_udp_mapping(&mut self, port: u16, protocol: ProtocolId) {
    43→        self.udp_mappings.insert(port, protocol);
    44→    }
    45→}
    46→
    47→impl ProtocolDetector for PortMappingDetector {
    48→    fn name(&self) -> &str {
    49→        "port-mapping"
    50→    }
    51→
    52→    fn transport(&self) -> TransportLayer {
    53→        // This detector handles both TCP and UDP
    54→        TransportLayer::Tcp
    55→    }
    56→
    57→    fn detect(&self, ctx: &DetectionContext<'_>) -> Option<DetectionResult> {
    58→        let protocol = match ctx.transport {
    59→            TransportLayer::Tcp => self
    60→                .tcp_mappings
    61→                .get(&ctx.dst_port)
    62→                .or_else(|| self.tcp_mappings.get(&ctx.src_port)),
    63→            TransportLayer::Udp => self
    64→                .udp_mappings
    65→                .get(&ctx.dst_port)
    66→                .or_else(|| self.udp_mappings.get(&ctx.src_port)),
    67→        }?;
    68→
    69→        Some(DetectionResult {
    70→            protocol: protocol.clone(),
    71→            confidence: 0.5,
    72→            method: DetectionMethod::PortMapping,
    73→            version: None,
    74→        })
    75→    }
    76→}
    77→
    78→/// Detects HTTP/2 and gRPC via connection preface and frame heuristics.
    79→pub struct GrpcDetector;
    80→
    81→impl ProtocolDetector for GrpcDetector {
    82→    fn name(&self) -> &str {
    83→        "grpc-magic-bytes"
    84→    }
    85→
    86→    fn transport(&self) -> TransportLayer {
    87→        TransportLayer::Tcp
    88→    }
    89→
    90→    fn detect(&self, ctx: &DetectionContext<'_>) -> Option<DetectionResult> {
    91→        if ctx.transport != TransportLayer::Tcp {
    92→            return None;
    93→        }
    94→
    95→        // Check for HTTP/2 connection preface
    96→        const H2_PREFACE: &[u8] = b"PRI * HTTP/2.0\r\n\r\nSM\r\n\r\n";
    97→        if ctx.initial_bytes.starts_with(H2_PREFACE) {
    98→            return Some(DetectionResult {
    99→                protocol: ProtocolId::new(ProtocolId::GRPC),
   100→                confidence: 0.95,
   101→                method: DetectionMethod::MagicBytes,
   102→                version: Some("h2".into()),
   103→            });
   104→        }
   105→
   106→        // Heuristic: HTTP/2 frame (9-byte header, type 0x00-0x09, length < 16MB)
   107→        if ctx.initial_bytes.len() >= 9 {
   108→            let len = u32::from_be_bytes([
   109→                0,
   110→                ctx.initial_bytes[0],
   111→                ctx.initial_bytes[1],
   112→                ctx.initial_bytes[2],
   113→            ]);
   114→            let frame_type = ctx.initial_bytes[3];
   115→            if len < 16_777_216 && frame_type <= 0x09 {
   116→                return Some(DetectionResult {
   117→                    protocol: ProtocolId::new(ProtocolId::HTTP2),
   118→                    confidence: 0.6,
   119→                    method: DetectionMethod::Heuristic,
   120→                    version: Some("h2".into()),
   121→                });
   122→            }
   123→        }
   124→
   125→        None
   126→    }
   127→}
   128→
   129→/// Detects ZMTP 3.x via greeting signature.
   130→pub struct ZmtpDetector;
   131→
   132→impl ProtocolDetector for ZmtpDetector {
   133→    fn name(&self) -> &str {
   134→        "zmtp-magic-bytes"
   135→    }
   136→
   137→    fn transport(&self) -> TransportLayer {
   138→        TransportLayer::Tcp
   139→    }
   140→
   141→    fn detect(&self, ctx: &DetectionContext<'_>) -> Option<DetectionResult> {
   142→        if ctx.transport != TransportLayer::Tcp {
   143→            return None;
   144→        }
   145→        if ctx.initial_bytes.len() < 10 {
   146→            return None;
   147→        }
   148→
   149→        // ZMTP 3.x signature: [0xFF, 8 padding bytes, 0x7F]
   150→        if ctx.initial_bytes[0] == 0xFF && ctx.initial_bytes[9] == 0x7F {
   151→            let version = if ctx.initial_bytes.len() >= 11 {
   152→                format!("3.{}", ctx.initial_bytes[10])
   153→            } else {
   154→                "3.x".into()
   155→            };
