   216→
   217→    fn export(&self, events: &[DebugEvent], writer: &mut dyn Write) -> Result<(), ExportError> {
   218→        let grpc_events: Vec<_> = events
   219→            .iter()
   220→            .filter(|e| e.transport == TransportKind::Grpc)
   221→            .collect();
   222→
   223→        let entries: Vec<_> = grpc_events.iter().map(|e| event_to_har_entry(e)).collect();
   224→
   225→        let non_grpc_count = events.len() - grpc_events.len();
